UPDATE shipment_request
SET status_num = (SELECT status_num FROM request_status WHERE status_name = '출하대기')
WHERE shipment_request_num = #{_parameter}

UPDATE lot
SET current_qty = current_qty - #{qty}
WHERE lot_num = #{lot_num}
  AND current_qty >= #{qty}

UPDATE shipment SET shipment_status = '출하완료'
WHERE shipment_num = #{_parameter}
  AND shipment_status = '출하대기'

UPDATE shipment_request
SET status_num = (SELECT status_num FROM request_status WHERE status_name = '출하완료')
WHERE shipment_request_num = #{_parameter}

UPDATE shipment SET shipment_status = '취소'
WHERE shipment_num = #{_parameter}
  AND shipment_status = '출하대기'

UPDATE shipment_request
SET status_num = (SELECT status_num FROM request_status WHERE status_name = '접수')
WHERE shipment_request_num = #{_parameter}

UPDATE shipment_lot
SET lot_num = #{child_lot_num}
WHERE shipment_num = #{shipment_num}
  AND lot_num      = #{parent_lot_num}
